// Minimal Service Worker to pass PWA criteria
self.addEventListener('install', (e) => {
    self.skipWaiting();
});

self.addEventListener('activate', (e) => {
    e.waitUntil(self.clients.claim());
});

self.addEventListener('fetch', (e) => {
    // Just pass through, no caching
    e.respondWith(fetch(e.request));
});

import { NextResponse } from 'next/server';
import { GoogleGenerativeAI } from '@google/generative-ai';
import { sql } from '@/lib/db';
import { auth } from '@clerk/nextjs/server';

// Initialize Gemini API
const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY || '');

export async function GET() {
    try {
        const { userId } = await auth();
        if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

        const links = await sql`SELECT * FROM links WHERE user_id = ${userId} ORDER BY created_at DESC;`;
        return NextResponse.json({ success: true, data: links });
    } catch (error: any) {
        console.error("Error fetching links:", error);
        return NextResponse.json({ error: 'Failed to fetch links' }, { status: 500 });
    }
}

export async function POST(req: Request) {
    try {
        const { userId } = await auth();
        if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

        const { url } = await req.json();

        if (!url) {
            return NextResponse.json({ error: 'URL is required' }, { status: 400 });
        }

        // 1. Fetch Metadata from Microlink
        console.log(`Fetching metadata for: ${url}`);
        let title, description, imageUrl;

        const ytRegex = /(?:youtube\.com\/(?:[^\/]+\/.+\/|(?:v|e(?:mbed)?)\/|.*[?&]v=)|youtu\.be\/)([^"&?\/\s]{11})/i;
        const ytMatch = url.match(ytRegex);

        try {
            const microlinkRes = await fetch(`https://api.microlink.io?url=${encodeURIComponent(url)}`);
            const microlinkData = await microlinkRes.json();

            if (microlinkData.status === 'success') {
                title = microlinkData.data.title;
                description = microlinkData.data.description;
                imageUrl = microlinkData.data.image?.url || null;
            }
        } catch (e) {
            console.error("Microlink fetch error:", e);
            // Ignore error, we will use fallback or fail below
        }

        if (ytMatch && ytMatch[1]) {
            const videoId = ytMatch[1];
            // Override or fallback thumbnail with YouTube's hqdefault
            imageUrl = `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`;

            try {
                const oembedRes = await fetch(`https://www.youtube.com/oembed?url=${encodeURIComponent(url)}&format=json`);
                if (oembedRes.ok) {
                    const oembedData = await oembedRes.json();
                    if (oembedData.title) title = oembedData.title;
                    if (oembedData.author_name) description = `YouTube Video by ${oembedData.author_name}`;
                }
            } catch (e) {
                console.error("YouTube oEmbed fetch error:", e);
            }
            // Absolute fallback if oembed fails
            if (!title) title = "YouTube Video";
            if (!description) description = "A video from YouTube";
        }

        if (!title && !imageUrl) {
            return NextResponse.json({ error: 'Failed to fetch metadata from URL' }, { status: 400 });
        }

        // 2. Categorize using Gemini + URL heuristics
        let categoryList: string[] = [];

        // Guaranteed domain-based tags
        const urlLower = url.toLowerCase();
        if (urlLower.includes('youtube.com') || urlLower.includes('youtu.be')) categoryList.push('YouTube');
        if (urlLower.includes('twitter.com') || urlLower.includes('x.com')) categoryList.push('X');
        if (urlLower.includes('instagram.com')) categoryList.push('Insta');
        if (urlLower.includes('github.com')) categoryList.push('GitHub');
        if (urlLower.includes('linkedin.com')) categoryList.push('LinkedIn');

        try {
            if (process.env.GEMINI_API_KEY) {
                const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash" });
                const prompt = `Analyze this link and generate up to 3 highly descriptive, single-word tags (e.g., 'AI', 'Design', 'Tech', 'React', 'News', 'Finance', 'Tutorial').
        
        Link URL: "${url}"
        Link Title: "${title || 'Unknown'}"
        Link Description: "${description || 'No description available'}"
        
        Rules:
        1. Return ONLY the comma-separated words.
        2. Do not include spaces after commas.
        3. Keep tags simple, one-word, and lowercased or properly capitalized.`;

                const result = await model.generateContent(prompt);
                const generatedTags = result.response.text().trim();

                // Parse generated tags, ensuring we just have clean string values
                const parsedTags = generatedTags.replace(/[^a-zA-Z0-9, ]/g, '').split(',')
                    .map(t => t.trim())
                    .filter(t => t.length > 0 && t.toLowerCase() !== 'misc');

                categoryList.push(...parsedTags);
            }
        } catch (error) {
            console.error("Gemini classification failed:", error);
            // Will fallback to just the domain tags or 'Misc'
        }

        // Deduplicate and slice to max 3 tags
        let category = Array.from(new Set(categoryList.map(t => t.charAt(0).toUpperCase() + t.slice(1)))).slice(0, 3).join(', ');

        if (!category) {
            category = "Misc";
        }

        const processedData = {
            url,
            title: title || 'Untitled',
            description: description || '',
            image_url: imageUrl,
            category: category,
        };

        // 3. Save to Neon
        try {
            const insertedData = await sql`
                INSERT INTO links (url, title, description, image_url, category, user_id)
                VALUES (${processedData.url}, ${processedData.title}, ${processedData.description}, ${processedData.image_url}, ${processedData.category}, ${userId})
                RETURNING *;
            `;

            return NextResponse.json({
                success: true,
                data: insertedData[0]
            });
        } catch (dbError) {
            console.error("Neon Error:", dbError);
            return NextResponse.json({ error: 'Failed to save to database', details: dbError }, { status: 500 });
        }

    } catch (error: any) {
        console.error("Error processing link:", error);
        return NextResponse.json({ error: error.message || 'Internal Server Error' }, { status: 500 });
    }
}

export async function DELETE(req: Request) {
    try {
        const { userId } = await auth();
        if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

        const url = new URL(req.url);
        const id = url.searchParams.get('id');

        if (!id) {
            return NextResponse.json({ error: 'Link ID is required' }, { status: 400 });
        }

        // Delete but ensure it's scoped to the user
        await sql`DELETE FROM links WHERE id = ${id} AND user_id = ${userId}`;

        return NextResponse.json({ success: true });
    } catch (error: any) {
        console.error("Error deleting link:", error);
        return NextResponse.json({ error: 'Failed to delete link' }, { status: 500 });
    }
}

"use client";

import { useEffect, useState, Suspense, useRef } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { Loader2, CheckCircle2 } from "lucide-react";

function ShareReceiver() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const [status, setStatus] = useState("Processing your shared link...");
    const hasProcessed = useRef(false);

    useEffect(() => {
        if (hasProcessed.current) return;
        hasProcessed.current = true;

        async function processSharedLink() {
            const sharedUrl = searchParams.get("url") || "";
            const sharedText = searchParams.get("text") || "";

            // Try to find a URL in the text if sharedUrl is empty (some apps share links inside text)
            let finalUrl = sharedUrl;
            if (!finalUrl && sharedText) {
                const urlMatch = sharedText.match(/https?:\/\/[^\s]+/);
                if (urlMatch) finalUrl = urlMatch[0];
            }

            if (!finalUrl) {
                setStatus("No valid link found to save.");
                setTimeout(() => router.push('/'), 2000);
                return;
            }

            setStatus("Saving link to your database...");
            try {
                const res = await fetch('/api/link', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ url: finalUrl })
                });

                if (res.ok) {
                    setStatus("Successfully saved!");
                } else {
                    setStatus("Failed to save the link. It might be invalid.");
                }
            } catch (e) {
                setStatus("An error occurred while saving.");
            }

            setTimeout(() => {
                router.push('/');
            }, 1000);
        }

        processSharedLink();
    }, [searchParams, router]);

    return (
        <div className="min-h-[60vh] flex items-center justify-center p-4">
            <div className="glass-card max-w-sm w-full p-8 text-center flex flex-col items-center gap-4">
                {status.includes("Success") ? (
                    <CheckCircle2 className="w-12 h-12 text-green-400" />
                ) : status.includes("valid") || status.includes("Fail") || status.includes("error") ? (
                    <div className="w-12 h-12 rounded-full bg-red-500/20 text-red-400 flex items-center justify-center font-bold text-xl">!</div>
                ) : (
                    <Loader2 className="w-12 h-12 text-indigo-400 animate-spin" />
                )}
                <h2 className="text-xl font-semibold text-white">{status}</h2>
                <p className="text-slate-400 text-sm">You will be redirected automatically.</p>
            </div>
        </div>
    );
}

export default function SharePage() {
    return (
        <Suspense fallback={<div className="min-h-screen flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-indigo-400" /></div>}>
            <ShareReceiver />
        </Suspense>
    );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { Plus, Link as LinkIcon, Loader2, BookmarkPlus, Sparkles } from "lucide-react";
import { cn } from "@/lib/utils";

export default function CreateLink({ onSuccess }: { onSuccess: () => void }) {
    const [url, setUrl] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState("");
    const [currentOrigin, setCurrentOrigin] = useState("");

    useEffect(() => {
        if (typeof window !== 'undefined') {
            setCurrentOrigin(window.location.origin);
        }
    }, []);

    const inputRef = useRef<HTMLInputElement>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!url) return;

        setIsLoading(true);
        setError(""); // Clear previous errors
        try {
            const res = await fetch('/api/link', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ url })
            });
            const result = await res.json();

            if (res.ok) {
                // Successfully processed
                setUrl("");
                onSuccess();
            } else {
                console.error("Error from API:", result.error);
                setError(result.error);
                alert(result.error);
            }
        } catch (err) {
            console.error(err);
            setError('Failed to save link');
            alert('Failed to save link');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div>
            <form onSubmit={handleSubmit} className="relative group">
                <div className={cn(
                    "absolute -inset-0.5 bg-gradient-to-r from-indigo-500 to-pink-500 rounded-2xl blur opacity-30 group-hover:opacity-50 transition duration-500",
                    isLoading && "opacity-70 animate-pulse"
                )}></div>
                <div className="relative flex items-center bg-[#131b2f] border border-white/10 rounded-2xl p-2 shadow-2xl transition-all">
                    <div className="pl-4 pr-3 text-slate-400">
                        <LinkIcon className="w-6 h-6" />
                    </div>
                    <input
                        type="url"
                        value={url}
                        onChange={(e) => setUrl(e.target.value)}
                        placeholder="Paste any URL here (e.g. from X, LinkedIn, Readcv...)"
                        className="flex-1 bg-transparent text-slate-200 placeholder-slate-500 outline-none text-lg py-3"
                        required
                        ref={inputRef}
                    />
                    <button
                        type="submit"
                        disabled={isLoading || !url}
                        className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-3 rounded-xl font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {isLoading ? (
                            <Loader2 className="w-5 h-5 animate-spin" />
                        ) : (
                            <>
                                <Sparkles className="w-5 h-5 text-indigo-200" />
                                <span>Save & Analyze</span>
                            </>
                        )}
                    </button>
                </div>
            </form>

            {currentOrigin && (
                <div className="mt-6 pt-6 border-t border-white/5 flex flex-col md:flex-row items-center justify-between gap-4">
                    <div className="text-sm text-slate-400 text-center md:text-left">
                        <p className="font-semibold text-slate-300">Quick Save via Bookmarklet</p>
                        <p>Drag this button to your bookmarks bar. Click it on any website to save the link instantly!</p>
                        <button
                            onClick={(e) => {
                                e.preventDefault();
                                navigator.clipboard.writeText(`javascript:(function(){window.location.href='${currentOrigin}/share?url='+encodeURIComponent(window.location.href)+'&text='+encodeURIComponent(document.title);})();`);
                                alert("Bookmarklet copied! Create a new bookmark in your browser and paste this code as the URL.");
                            }}
                            className="text-xs text-indigo-400 hover:text-indigo-300 mt-1"
                        >
                            Dragging not working? Click here to copy the code manually.
                        </button>
                    </div>
                    <a
                        href={`javascript:(function(){window.location.href='${currentOrigin}/share?url='+encodeURIComponent(window.location.href)+'&text='+encodeURIComponent(document.title);})();`}
                        onClick={(e) => e.preventDefault()}
                        className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-lg text-sm font-medium text-slate-300 w-fit cursor-grab transition-colors"
                        title="Drag to bookmarks bar"
                    >
                        <BookmarkPlus className="w-4 h-4" />
                        Save to LinkManager
                    </a>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ExternalLink, Tag, MoreVertical, Trash2 } from "lucide-react";

import { LinkType } from "./LinkList";

export default function LinkCard({ link, index, onDelete }: { link: LinkType; index: number; onDelete?: (id: string) => void }) {
    const [isMenuOpen, setIsMenuOpen] = useState(false);

    const handleDelete = (e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();
        if (onDelete) onDelete(link.id);
        setIsMenuOpen(false);
    };

    return (
        <motion.a
            href={link.url}
            target="_blank"
            rel="noopener noreferrer"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
            className="glass-card flex flex-col overflow-hidden group hover:-translate-y-1 block relative"
        >
            {/* Absolute positioning for 3-dot menu */}
            <div className="absolute top-3 right-3 z-20">
                <button
                    onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsMenuOpen(!isMenuOpen); }}
                    className="p-1.5 rounded-full bg-slate-900/60 text-slate-300 hover:text-white hover:bg-slate-800 transition-colors backdrop-blur-md"
                >
                    <MoreVertical className="w-4 h-4" />
                </button>

                <AnimatePresence>
                    {isMenuOpen && (
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            className="absolute right-0 mt-1 w-32 bg-slate-800 border border-slate-700 rounded-lg shadow-xl overflow-hidden"
                        >
                            <button
                                onClick={handleDelete}
                                className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-500 hover:bg-slate-700 transition-colors text-left"
                            >
                                <Trash2 className="w-4 h-4" />
                                Delete
                            </button>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Image Banner */}
            {link.image_url ? (
                <div className="h-40 w-full overflow-hidden bg-white/5 border-b border-white/5">
                    <img
                        src={link.image_url}
                        alt={link.title}
                        className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                        onError={(e) => {
                            (e.target as HTMLImageElement).src = 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" viewBox="0 0 100 100" fill="none"><rect width="100%" height="100%" fill="%231e1b4b"/></svg>';
                        }}
                    />
                </div>
            ) : (
                <div className="h-40 w-full bg-indigo-900/20" />
            )}

            {/* Content */}
            <div className="p-5 flex-1 flex flex-col">
                <div className="flex justify-between items-start gap-2 mb-2">
                    <h3 className="text-lg font-semibold leading-tight line-clamp-2 text-slate-100 group-hover:text-indigo-400 transition-colors">
                        {link.title}
                    </h3>
                    <ExternalLink className="w-4 h-4 text-slate-500 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0" />
                </div>

                <p className="text-sm text-slate-400 line-clamp-2 flex-1 mb-4">
                    {link.description}
                </p>

                <div className="flex flex-wrap items-center gap-2 mt-auto">
                    {(link.category || "Misc").split(',').map(tag => tag.trim()).filter(Boolean).map((tag, i) => (
                        <span key={i} className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-indigo-500/10 text-indigo-300 text-xs font-medium border border-indigo-500/20">
                            <Tag className="w-3 h-3" />
                            {tag}
                        </span>
                    ))}
                </div>
            </div>
        </motion.a>
    );
}
